const crypto = require('crypto');
const payload = $input.first().json.body;
const sig = $input.first().json.headers['stripe-signature'];
const secret = $env.STRIPE_WEBHOOK_SECRET;

// Parse Stripe signature
const elements = sig.split(',');
const timestamp = elements.find(e => e.startsWith('t=')).split('=')[1];
const signature = elements.find(e => e.startsWith('v1=')).split('=')[1];

// Verify signature
const signedPayload = `${timestamp}.${JSON.stringify(payload)}`;
const expectedSig = crypto.createHmac('sha256', secret).update(signedPayload).digest('hex');

if (expectedSig !== signature) {
  throw new Error('Invalid webhook signature');
}

// Parse event
const event = typeof payload === 'string' ? JSON.parse(payload) : payload;
return [{ json: event }];

const event = $input.first().json;
const pi = event.data.object;
const amount = pi.amount;
const currency = pi.currency.toUpperCase();
const paymentMethod = pi.payment_method_types ? pi.payment_method_types[0] : 'card';
const customerEmail = pi.receipt_email || 'N/A';

// Format JPY amount
const formattedAmount = currency === 'JPY' 
  ? `¥${amount.toLocaleString()}` 
  : `${(amount / 100).toFixed(2)} ${currency}`;

// Determine payment method display name
const methodNames = {
  'card': 'Credit Card',
  'paypay': 'PayPay',
  'konbini': 'Konbini',
  'customer_balance': 'Bank Transfer'
};
const methodDisplay = methodNames[paymentMethod] || paymentMethod;

return [{
  json: {
    payment_intent_id: pi.id,
    amount: amount,
    formatted_amount: formattedAmount,
    currency: currency,
    payment_method: methodDisplay,
    customer_email: customerEmail,
    customer_id: pi.customer,
    description: pi.description || 'N/A',
    created: new Date(pi.created * 1000).toISOString(),
    receipt_url: pi.charges?.data?.[0]?.receipt_url || 'N/A'
  }
}];

